#define SERVER_FROM(v1)                                               \
    if (auto v1 = f.find(#v1); v1 != f.end()) {                       \
        if (auto cvtd = server_cvt_s2t<decltype(t.v1)>(v1->second)) { \
            t.v1 = *cvtd;                                             \
        } else {                                                      \
            return {};                                                \
        }                                                             \
    } else {                                                          \
        return {};                                                    \
    }

// Construct a from_form method for Type
#define SERVER_DESERIALIZABLE(Type, ...)                          \
    static auto from_form(const Form &f) -> std::optional<Type> { \
        Type t;                                                   \
        SERVER_EXPAND(SERVER_PASTE(SERVER_FROM, __VA_ARGS__))     \
        return t;                                                 \
    }

// Convert a std::string into type T, return {} if unable to convert
template<typename T>
auto server_cvt_s2t(const std::string &str) -> std::optional<T> {
    std::istringstream iss(str);
    T v;

    if constexpr (std::is_same_v<std::string, T>) {
        return str;
    }

    if (iss >> v && iss.eof()) {
        return v;
    }

    return {};
}

// Form data used inside a Request
using Form = std::unordered_map<std::string, std::string>;

namespace Forms {
    // Get form data from a Request bodies last line
    auto parse(const std::string &data) -> Form {
        Form form;
        std::istringstream stream(data);
        std::string token;

        // form data comes in as key1=value&key2=value
        // split each key value pair at the '&'
        // then convert each token into a k/v pair
        // store the k/v inside of a Form type
        while (std::getline(stream, token, '&')) {
            const auto equal = token.find('=');
            if (equal != std::string::npos) {
                const auto k = token.substr(0, equal);
                const auto v = token.substr(equal + 1);
                form[k]      = v;
            }
        }

        return form;
    }
}// namespace Forms